import{_ as s,o as a,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const d=JSON.parse('{"title":"Business Page","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/business-page.md","filePath":"advanced/business-page.md"}'),o={name:"advanced/business-page.md"};function r(n,e,l,u,p,c){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="business-page" tabindex="-1">Business Page <a class="header-anchor" href="#business-page" aria-label="Permalink to &quot;Business Page&quot;">​</a></h1><p>Create a public profile for your business that customers can visit to learn about your services and request quotes.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Your business page is a public web page that showcases:</p><ul><li>Your company information</li><li>Services you offer</li><li>Contact details</li><li>Social media links</li><li>A quote request form</li></ul><h2 id="setting-up-your-business-page" tabindex="-1">Setting up your business page <a class="header-anchor" href="#setting-up-your-business-page" aria-label="Permalink to &quot;Setting up your business page&quot;">​</a></h2><ol><li>Go to <strong>Company</strong> settings</li><li>Fill in your <strong>business profile</strong> section: <ul><li><strong>Description</strong> — A brief overview of your business</li><li><strong>Services</strong> — List the services you offer</li><li><strong>Website</strong> — Your company website URL</li><li><strong>Social media</strong> — Links to your social profiles</li></ul></li><li>Your business page is automatically available at a unique URL</li></ol><h2 id="business-page-url" tabindex="-1">Business page URL <a class="header-anchor" href="#business-page-url" aria-label="Permalink to &quot;Business page URL&quot;">​</a></h2><p>Your page is accessible at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://app.mycompanydesk.com/portal/{your-company-slug}</span></span></code></pre></div><p>Share this link on your website, social media, or business cards.</p><h2 id="quote-request-form" tabindex="-1">Quote request form <a class="header-anchor" href="#quote-request-form" aria-label="Permalink to &quot;Quote request form&quot;">​</a></h2><p>Visitors to your business page can submit a quote request:</p><ol><li>They fill in their <strong>name</strong>, <strong>email</strong>, and <strong>service description</strong></li><li>The request is submitted</li><li>You receive a notification</li><li>The request appears in <strong>Quotes &gt; Requests</strong></li></ol><h3 id="rate-limiting" tabindex="-1">Rate limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate limiting&quot;">​</a></h3><p>To prevent spam, quote requests are limited to 1 per 15 minutes per IP address.</p><h2 id="managing-requests" tabindex="-1">Managing requests <a class="header-anchor" href="#managing-requests" aria-label="Permalink to &quot;Managing requests&quot;">​</a></h2><p>See <a href="/features/quotes#quote-requests">Quotes — Quote Requests</a> for details on managing incoming requests.</p><h2 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h2><p>Your business page uses your company branding:</p><ul><li>Company logo</li><li>Accent color</li><li>Company name and details</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Keep your services list up to date</li><li>Add a link to your business page on your website</li><li>Respond to quote requests promptly for better conversion</li><li>Use the quote request workflow to track leads</li></ul>',23)])])}const h=s(o,[["render",r]]);export{d as __pageData,h as default};
